/* ==========================================
   Cloud Sync & Model Update Screen
   ========================================== */

/* ── Phone Frame (reuse profile pattern) ── */
.phone-frame {
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
  background: #F0F4FF;
  padding: 20px;
}

.cs-screen {
  width: 390px;
  min-height: 844px;
  background: #F5F7FB;
  border-radius: 48px;
  box-shadow: 0 30px 80px rgba(0,0,0,0.22), inset 0 0 0 2px #E2E8F0;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  position: relative;
}

/* ── Status Bar ── */
.dp-status-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px 28px 4px;
  background: #fff;
  font-size: 12px;
  font-weight: 600;
  color: #1F2937;
}
.status-icons {
  display: flex;
  align-items: center;
  gap: 5px;
  font-size: 13px;
}
.battery-text { font-size: 11px; font-weight: 700; }

/* ── Top Nav ── */
.dp-topnav {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 8px 20px 10px;
  background: #fff;
}
.dp-logo { height: 36px; object-fit: contain; }
.dp-bell {
  position: relative;
  color: #374151;
  font-size: 20px;
  text-decoration: none;
}
.bell-dot {
  position: absolute;
  top: 0; right: 0;
  width: 8px; height: 8px;
  background: #EF4444;
  border-radius: 50%;
  border: 1.5px solid #fff;
}

/* ── Scroll Area ── */
.cs-scroll {
  flex: 1;
  overflow-y: auto;
  padding: 0 16px 16px;
  scrollbar-width: none;
}
.cs-scroll::-webkit-scrollbar { display: none; }

/* ── Page Header ── */
.cs-page-header {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 18px 0 16px;
  background: #F5F7FB;
}
.cs-back-btn {
  width: 36px; height: 36px;
  border-radius: 50%;
  background: #fff;
  display: flex; align-items: center; justify-content: center;
  color: #374151;
  font-size: 14px;
  box-shadow: 0 1px 4px rgba(0,0,0,0.10);
  text-decoration: none;
  flex-shrink: 0;
  margin-top: 4px;
}
.cs-title-block { flex: 1; }
.cs-page-title {
  font-size: 22px;
  font-weight: 800;
  color: #1F2937;
  margin: 0 0 6px;
  line-height: 1.25;
  text-align: center;
}
.cs-page-sub {
  font-size: 12.5px;
  color: #6B7280;
  text-align: center;
  margin: 0;
  line-height: 1.5;
}

/* ── Section Labels ── */
.cs-section-label {
  font-size: 15px;
  font-weight: 700;
  color: #1F2937;
  margin-bottom: 10px;
}
.cs-section-label-mt { margin-top: 18px; }

/* ── Generic Card ── */
.cs-card {
  background: #fff;
  border-radius: 16px;
  box-shadow: 0 2px 8px rgba(0,0,0,0.06);
  margin-bottom: 12px;
}

/* ── Cloud Sync Card ── */
.cs-sync-card {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px;
  gap: 12px;
}
.cs-sync-left {
  display: flex;
  align-items: center;
  gap: 14px;
  flex: 1;
}
.cs-cloud-icon-wrap {
  width: 52px; height: 52px;
  border-radius: 14px;
  background: #EEF2FF;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
}
.cs-cloud-icon {
  font-size: 24px;
  color: #4361EE;
}
.cs-sync-info { display: flex; flex-direction: column; gap: 5px; }
.cs-sync-row {
  display: flex;
  align-items: center;
  gap: 7px;
  font-size: 12.5px;
  color: #374151;
}
.cs-row-icon {
  font-size: 12px;
  color: #9CA3AF;
  width: 14px;
  text-align: center;
}
.cs-synced-text { color: #2563EB; font-weight: 600; }
.cs-check-badge {
  font-size: 24px;
  color: #22C55E;
  flex-shrink: 0;
}

/* ── Primary Button ── */
.cs-btn-primary {
  width: 100%;
  padding: 14px;
  background: #2563EB;
  color: #fff;
  border: none;
  border-radius: 12px;
  font-size: 15px;
  font-weight: 700;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  cursor: pointer;
  margin-bottom: 4px;
  transition: background 0.2s;
}
.cs-btn-primary:hover { background: #1D4ED8; }
.cs-btn-primary:disabled { opacity: 0.7; cursor: not-allowed; }

/* ── Models Card ── */
.cs-models-card { padding: 4px 0; }
.cs-model-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 16px;
}
.cs-model-left {
  display: flex;
  align-items: center;
  gap: 12px;
}
.cs-model-icon {
  width: 40px; height: 40px;
  border-radius: 12px;
  display: flex; align-items: center; justify-content: center;
  font-size: 18px;
}
.cs-mi-teal { background: #CCFBF1; color: #0D9488; }
.cs-mi-purple { background: #EDE9FE; color: #7C3AED; }
.cs-model-name { font-size: 14px; font-weight: 600; color: #1F2937; }
.cs-model-sub { font-size: 12px; color: #9CA3AF; }
.cs-model-right {
  display: flex;
  align-items: center;
  gap: 8px;
}
.cs-model-ver { font-size: 13px; font-weight: 600; color: #374151; }
.cs-model-check { font-size: 20px; color: #22C55E; }
.cs-model-divider {
  height: 1px;
  background: #F3F4F6;
  margin: 0 16px;
}

/* ── Update Available Card ── */
.cs-update-card {
  background: #fff;
  border: 1.5px solid #BFDBFE;
  border-radius: 16px;
  padding: 16px;
  margin-bottom: 12px;
  box-shadow: 0 2px 8px rgba(37,99,235,0.07);
}
.cs-update-header {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  margin-bottom: 14px;
}
.cs-update-icon-wrap {
  width: 44px; height: 44px;
  border-radius: 12px;
  background: #DBEAFE;
  display: flex; align-items: center; justify-content: center;
  font-size: 20px;
  color: #2563EB;
  flex-shrink: 0;
}
.cs-update-info { flex: 1; }
.cs-update-title {
  font-size: 15px;
  font-weight: 700;
  color: #2563EB;
  margin-bottom: 3px;
}
.cs-update-version {
  display: inline-block;
  background: #DBEAFE;
  color: #1D4ED8;
  font-size: 12px;
  font-weight: 700;
  padding: 2px 10px;
  border-radius: 999px;
  margin-bottom: 3px;
}
.cs-update-date { font-size: 12px; color: #6B7280; }
.cs-update-chev { font-size: 14px; color: #9CA3AF; margin-top: 4px; }

.cs-update-features {
  display: flex;
  flex-direction: column;
  gap: 8px;
  margin-bottom: 16px;
}
.cs-feature-row {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 13px;
  color: #374151;
}
.cs-feat-icon {
  width: 20px;
  text-align: center;
  color: #6B7280;
  font-size: 13px;
}

.cs-btn-download { margin-top: 4px; margin-bottom: 0; }

/* ── Auto-update Row ── */
.cs-autoupdate-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 14px 16px;
  cursor: pointer;
}
.cs-autoupdate-left {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 14px;
  color: #374151;
  font-weight: 500;
}
.cs-auto-icon { font-size: 16px; color: #6B7280; }
.cs-auto-on { color: #2563EB; font-weight: 700; }
.cs-auto-chev { font-size: 13px; color: #9CA3AF; }

/* ── Bottom Nav ── */
.dp-bottom-nav {
  display: flex;
  justify-content: space-around;
  align-items: center;
  padding: 10px 0 18px;
  background: #fff;
  border-top: 1px solid #F3F4F6;
  flex-shrink: 0;
}
.dp-bottom-nav .nav-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
  text-decoration: none;
  color: #9CA3AF;
  font-size: 10px;
  font-weight: 500;
}
.dp-bottom-nav .nav-item i { font-size: 18px; }
.dp-bottom-nav .nav-item.nav-active { color: #2563EB; }

